import React, {useState, useRef} from 'react'
import styled from 'styled-components'

const CardWrapper = styled.div `
display:flex;
flex-direction:column;
margin:30px 10px;
width:200px;

`
const ListingTime = styled.div `
font-size:0.4rem;
color:grey;
`

const Hr = styled.div `
width:100%;
height:1px;
background-color:grey;
`

const ListingTitleWrapper = styled.div `
display:flex;
justify-content:space-between;
`

const ListingTitle = styled.div `
font-size:0.8rem;
font-weight:900;
`

const ListingSize = styled.div `
font-size:0.8rem;
font-weight:900;
`
const ListingContent = styled.div ``


const ListingFooterWrapper = styled.div `
display:flex;
justify-content:space-between;
`

const ListingPrice = styled.div `
font-size:0.7rem;
font-weight:900;
`

const Love = styled.div ``

export default function ListingCard ({children}) {


	return (
		<CardWrapper>
			<CardImage></CardImage>
			<ListingTime></ListingTime>
			<Hr/>
			<ListingTitleWrapper>
				<ListingTitle></ListingTitle>
				<ListingSize></ListingSize>
			</ListingTitleWrapper>
			<ListingContent></ListingContent>
			<ListingFooterWrapper>
				<ListingPrice></ListingPrice>
				<Love></Love>
			</ListingFooterWrapper>
		</CardWrapper>
	)
}
